import{_ as o,c as t,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"업데이트 로그: 버전 기록 | opencode-md-table-formatter","description":"opencode-md-table-formatter의 버전 진화와 새로운 기능을 알아보세요. 자동 포맷팅 및 너비 캐싱 등 v0.1.0 기능을 확인하세요.","frontmatter":{"title":"업데이트 로그: 버전 기록 | opencode-md-table-formatter","sidebarTitle":"버전 변경 사항 개요","subtitle":"업데이트 로그: 버전 기록 및 변경 사항","description":"opencode-md-table-formatter의 버전 진화와 새로운 기능을 알아보세요. 자동 포맷팅 및 너비 캐싱 등 v0.1.0 기능을 확인하세요.","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"ko/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"ko/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),a={name:"ko/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(n,e,s,d,c,g){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="업데이트-로그-버전-기록-및-변경-사항" tabindex="-1">업데이트 로그: 버전 기록 및 변경 사항 <a class="header-anchor" href="#업데이트-로그-버전-기록-및-변경-사항" aria-label="Permalink to &quot;업데이트 로그: 버전 기록 및 변경 사항&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">학습 후 할 수 있는 것</p><ul><li>플러그인의 버전 진화 과정 추적</li><li>각 버전의 새로운 기능 및 수정 사항 이해</li><li>알려진 제한 사항 및 기술 세부사항 파악</li><li>향후 기능 향상 가능성 이해</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="새로운-기능" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><p>이것은 opencode-md-table-formatter의 <strong>초기 릴리스 버전</strong>으로, 다음 핵심 기능이 포함되어 있습니다:</p><ul><li><strong>자동 테이블 포맷팅</strong>: <code>experimental.text.complete</code> 훅을 통해 AI가 생성한 Markdown 테이블을 자동으로 포맷팅</li><li><strong>숨김 모드 지원</strong>: 너비를 계산할 때 숨겨진 Markdown 기호(<code>**</code>, <code>*</code> 등)를 올바르게 처리</li><li><strong>중첩 Markdown 처리</strong>: 다중 패스 스트리핑 알고리즘을 사용하여 임의 깊이의 중첩 Markdown 구문 지원</li><li><strong>코드 블록 보호</strong>: 인라인 코드(<code>`code`</code>) 내의 Markdown 기호는 리터럴 형식으로 유지되며 너비 계산에 참여하지 않음</li><li><strong>정렬 방식 지원</strong>: 왼쪽 정렬(<code>---</code> 또는 <code>:---</code>), 가운데 정렬(<code>:---:</code>), 오른쪽 정렬(<code>---:</code>) 지원</li><li><strong>너비 캐싱 최적화</strong>: 문자열 표시 너비 계산 결과를 캐싱하여 성능 향상</li><li><strong>유효하지 않은 테이블 검증</strong>: 테이블 구조를 자동으로 검증하고 유효하지 않은 테이블에 오류 주석 추가</li><li><strong>다중 문자 지원</strong>: Emoji, Unicode 문자, 빈 셀, 초과 길이 콘텐츠 지원</li><li><strong>조용한 오류 처리</strong>: 포맷팅 실패가 OpenCode 워크플로우를 중단하지 않음</li></ul><h3 id="기술-세부사항" tabindex="-1">기술 세부사항 <a class="header-anchor" href="#기술-세부사항" aria-label="Permalink to &quot;기술 세부사항&quot;">​</a></h3><p>이 버전은 약 <strong>230줄의 프로덕션 준비된 TypeScript 코드</strong>를 포함합니다:</p><ul><li><strong>12개 함수</strong>: 명확한 책임과 잘 분리된 구조</li><li><strong>타입 안전성</strong>: <code>Hooks</code> 인터페이스를 올바르게 사용</li><li><strong>스마트 캐시 정리</strong>: 작업 수가 100회를 초과하거나 캐시 항목이 1000개를 초과할 때 정리 트리거</li><li><strong>다중 패스 정규식 처리</strong>: 임의 중첩 깊이의 Markdown 기호 스트리핑 지원</li></ul><div class="tip custom-block"><p class="custom-block-title">캐싱 메커니즘</p><p>캐시는 반복 콘텐츠의 너비 계산을 최적화하도록 설계되었습니다. 예를 들어, 테이블에서 동일한 셀 텍스트가 여러 번 나타나는 경우 너비는 한 번만 계산되며 이후에는 캐시에서 직접 읽습니다.</p></div><h3 id="알려진-제한-사항" tabindex="-1">알려진 제한 사항 <a class="header-anchor" href="#알려진-제한-사항" aria-label="Permalink to &quot;알려진 제한 사항&quot;">​</a></h3><p>이 버전은 다음 시나리오를 지원하지 않습니다:</p><ul><li><strong>HTML 테이블</strong>: Markdown 파이프 테이블(Pipe Table)만 지원</li><li><strong>다중 행 셀</strong>: <code>&lt;br&gt;</code> 태그를 포함하는 셀은 지원하지 않음</li><li><strong>구분선 없는 테이블</strong>: 테이블이 구분선(<code>|---|</code>)을 포함해야 포맷팅됨</li><li><strong>종속성 요구사항</strong>: <code>@opencode-ai/plugin</code> &gt;= 0.13.7 필요(공개되지 않은 <code>experimental.text.complete</code> 훅 사용)</li></ul><div class="info custom-block"><p class="custom-block-title">버전 요구사항</p><p>플러그인은 OpenCode &gt;= 1.0.137 및 <code>@opencode-ai/plugin</code> &gt;= 0.13.7이 필요합니다.</p></div><hr><h2 id="향후-계획" tabindex="-1">향후 계획 <a class="header-anchor" href="#향후-계획" aria-label="Permalink to &quot;향후 계획&quot;">​</a></h2><p>다음 기능은 향후 버전에서 구현될 예정입니다:</p><ul><li><strong>구성 옵션</strong>: 사용자 정의 최소/최대 열 너비, 특정 기능 비활성화 지원</li><li><strong>헤더 없는 테이블 지원</strong>: 헤더 행이 없는 테이블 포맷팅</li><li><strong>성능 최적화</strong>: 대규모 테이블(100+ 행)에 대한 성능 분석 및 최적화</li><li><strong>추가 정렬 옵션</strong>: 정렬 방식의 구문 및 기능 확장</li></ul><div class="tip custom-block"><p class="custom-block-title">기여하기</p><p>기능 제안이 있거나 코드를 기여하고 싶다면 <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a>에서 아이디어를 제출해 주세요.</p></div><hr><h2 id="변경-기록-형식-설명" tabindex="-1">변경 기록 형식 설명 <a class="header-anchor" href="#변경-기록-형식-설명" aria-label="Permalink to &quot;변경 기록 형식 설명&quot;">​</a></h2><p>이 프로젝트의 업데이트 로그는 <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> 형식을 따르며, 버전 번호는 <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">시맨틱 버전 관리(Semantic Versioning)</a>을 따릅니다.</p><p><strong>버전 번호 형식</strong>: <code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>: 호환되지 않는 API 변경</li><li><strong>MINOR</strong>: 호환되는 새로운 기능</li><li><strong>PATCH</strong>: 호환되는 문제 수정</li></ul><p><strong>변경 유형</strong>:</p><ul><li><strong>Added</strong>: 새로운 기능</li><li><strong>Changed</strong>: 기존 기능의 변경</li><li><strong>Deprecated</strong>: 곧 제거될 기능</li><li><strong>Removed</strong>: 제거된 기능</li><li><strong>Fixed</strong>: 문제 수정</li><li><strong>Security</strong>: 보안 관련 수정</li></ul><hr><h2 id="권장-읽기-순서" tabindex="-1">권장 읽기 순서 <a class="header-anchor" href="#권장-읽기-순서" aria-label="Permalink to &quot;권장 읽기 순서&quot;">​</a></h2><p>새로운 사용자라면 다음 순서대로 학습하는 것을 권장합니다:</p><ol><li><a href="./../../start/getting-started/">1분 빠른 시작: 설치 및 구성</a> — 빠르게 시작하기</li><li><a href="./../../start/features/">기능 개요: 자동 포맷팅의 마법</a> — 핵심 기능 이해</li><li><a href="./../../faq/troubleshooting/">자주 묻는 질문: 테이블이 포맷팅되지 않는 문제 해결</a> — 문제 해결</li><li><a href="./../../appendix/limitations/">알려진 제한 사항: 플러그인의 경계는 어디까지인가</a> — 제한 사항 이해</li></ol>',31)])])}const m=o(a,[["render",i]]);export{h as __pageData,m as default};
